const invoice = $input.first().json;
const customer = $('Lookup Customer').first().json;

const today = new Date();
today.setHours(0, 0, 0, 0);

const dueDate = new Date(invoice['Due Date']);
dueDate.setHours(0, 0, 0, 0);

const daysDiff = Math.floor((today - dueDate) / (1000 * 60 * 60 * 24));
const nextReminder = invoice['Next Reminder Date'] ? new Date(invoice['Next Reminder Date']) : null;

let reminderStage = 'no_action';
let reminderTone = '';

if (nextReminder && nextReminder > today) {
  reminderStage = 'no_action';
} else if (daysDiff <= -3 && daysDiff > -4) {
  reminderStage = 't_minus_3';
  reminderTone = 'friendly';
} else if (daysDiff >= -1 && daysDiff <= 1) {
  reminderStage = 'due_date';
  reminderTone = 'reminder';
} else if (daysDiff >= 2 && daysDiff <= 5) {
  reminderStage = 't_plus_3';
  reminderTone = 'firm';
} else if (daysDiff >= 6 && daysDiff <= 10) {
  reminderStage = 't_plus_7';
  reminderTone = 'collections';
} else if (daysDiff >= 11) {
  reminderStage = 't_plus_14';
  reminderTone = 'escalation';
}

// If already reminded at this stage, skip
const reminderCount = parseInt(invoice['Reminder Count'] || '0');

return {
  json: {
    ...invoice,
    customerName: customer['Legal Name'] || customer['Trading Name'] || '',
    customerEmail: customer['Email'] || '',
    customerPhone: customer['Phone'] || '',
    preferredChannel: customer['Preferred Channel'] || 'Email',
    riskFlag: customer['Risk Flag'] || 'Low',
    reminderStage: reminderStage,
    reminderTone: reminderTone,
    daysPastDue: daysDiff,
    dueDate: invoice['Due Date'],
    invoiceNumber: invoice['Invoice Number'],
    total: invoice['Total'],
    balanceDue: invoice['Balance Due'] || invoice['Total'],
    reminderCount: reminderCount,
  }
};

const input = $input.first().json;
const body = input.body || input;

const invoiceNumber = body.invoice_number || body.invoiceNumber || '';
const reason = body.reason || body.dispute_reason || 'Not specified';
const details = body.details || body.description || '';
const customerName = body.customer_name || body.customerName || '';
const customerEmail = body.customer_email || body.customerEmail || '';

if (!invoiceNumber) {
  throw new Error('Missing required field: invoice_number');
}

// Assign dispute owner based on reason category
let disputeOwner = 'accounts@anyvisionmedia.com';
let priority = 'Normal';

const reasonLower = reason.toLowerCase();
if (reasonLower.includes('overcharge') || reasonLower.includes('incorrect amount')) {
  disputeOwner = 'accounts@anyvisionmedia.com';
  priority = 'High';
} else if (reasonLower.includes('service') || reasonLower.includes('quality')) {
  disputeOwner = 'ian@anyvisionmedia.com';
  priority = 'High';
} else if (reasonLower.includes('duplicate')) {
  disputeOwner = 'accounts@anyvisionmedia.com';
  priority = 'Normal';
} else if (reasonLower.includes('not received') || reasonLower.includes('wrong')) {
  disputeOwner = 'accounts@anyvisionmedia.com';
  priority = 'High';
}

return {
  json: {
    invoiceNumber: invoiceNumber,
    disputeReason: reason,
    disputeDetails: details,
    customerName: customerName,
    customerEmail: customerEmail,
    disputeOwner: disputeOwner,
    priority: priority,
    disputeDate: new Date().toISOString().split('T')[0],
    status: 'Disputed',
  }
};

const allItems = $input.all();

let totalProcessed = 0;
let remindersSent = 0;
let escalations = 0;
let skipped = 0;
const summaryLines = [];

for (const item of allItems) {
  totalProcessed++;
  const stage = item.json.reminderStage || item.json.lastReminderStage || 'unknown';
  const inv = item.json.invoiceNumber || item.json['Invoice Number'] || 'N/A';

  if (stage === 'no_action' || stage === 'unknown') {
    skipped++;
  } else {
    remindersSent++;
    if (stage === 't_plus_14') escalations++;
    summaryLines.push(`${inv}: ${stage}`);
  }
}

const summary = [
  `Collections Run Complete - ${new Date().toISOString().split('T')[0]}`,
  `Total Invoices Processed: ${totalProcessed}`,
  `Reminders Sent: ${remindersSent}`,
  `Escalations: ${escalations}`,
  `Skipped (no action): ${skipped}`,
  '',
  'Details:',
  ...summaryLines,
].join('\n');

return {
  json: {
    summary: summary,
    totalProcessed: totalProcessed,
    remindersSent: remindersSent,
    escalations: escalations,
    skipped: skipped,
    completedAt: new Date().toISOString(),
  }
};
